namespace sv_41a91e4fe32d401cab669a720ec3860c.Services;

/// <summary>
/// Scoped service that holds the current low-stock alert count and notifies
/// all subscribers when new data arrives. Scoped lifetime ensures each
/// circuit (user) gets an independent instance.
/// </summary>
public class InventoryAlertService
{
    private static readonly Random s_random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate latency + random result (0–15)
        var count = s_random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Updates the cached alert count and notifies all subscribers.
    /// Called by whichever component owns the polling loop.
    /// </summary>
    public void UpdateAlertCount(int newCount)
    {
        CurrentAlertCount = newCount;
        OnChange?.Invoke();
    }
}

