@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable
@using sv_41a91e4fe32d401cab669a720ec3860c.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text">
            <strong>@Warehouse?.Name</strong>
            <span class="text-muted">(@Warehouse?.WarehouseId)</span>
        </p>
    </div>
</div>

<div class="card mb-4" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger ms-2">@AlertService.CurrentAlertCount</span>
            }
            else
            {
                <span class="badge bg-success ms-2">0</span>
            }
        </h5>
        <p class="text-muted mb-0">Polling every 10 seconds. Last check: @_lastCheck?.ToString("T")</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private CancellationTokenSource? _cts;
    private Action? _handler;
    private DateTime? _lastCheck;

    protected override void OnInitialized()
    {
        // Subscribe so we re-render when polling updates the count
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling whenever the warehouse changes
        await RestartPollingAsync();
    }

    private async Task RestartPollingAsync()
    {
        // Cancel any existing polling loop
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = new CancellationTokenSource();
        _ = PollAsync(_cts.Token);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        // Do an immediate first poll, then every 10 seconds
        while (!ct.IsCancellationRequested)
        {
            try
            {
                var warehouseId = Warehouse?.WarehouseId ?? "WH-1";
                var count = await AlertService.GetLowStockCountAsync(warehouseId);

                _lastCheck = DateTime.Now;

                // This fires OnChange, notifying ALL subscribers (sidebar badge, etc.)
                AlertService.UpdateAlertCount(count);

                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

